const PROCESSING_FEE = 5;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
};

const calculateBasePremium = (items: { type: string }[]): number =>
  items.reduce((sum, item) => sum + (BASE_PREMIUMS[item.type] ?? 0), 0);

export function processScenario(scenario: { steps: { op: string; items?: { type: string }[] }[] }): { results: unknown[] } {
  const results = scenario.steps.map((step) => {
    const premium = calculateBasePremium(step.items ?? []) + PROCESSING_FEE;
    return { premium };
  });
  return { results };
}

